USE hacker_db;

CREATE TABLE IF NOT EXISTS h_log (
    id          INT AUTO_INCREMENT PRIMARY KEY,
    timestamp   DATETIME     NOT NULL,
    ip_sorgente VARCHAR(45),
    alias       VARCHAR(100),
    azione      VARCHAR(50),
    esito       ENUM('successo','fallito') DEFAULT 'successo',
    note        TEXT
);


